function infoCo_injectToCodex()
    Player():invokeFunction('ui/cosmiccodex', 'addCategory', 'co_cat', 'Cosmic Overhaul'%_t, 'data/textures/icons/cog.png')
    Player():invokeFunction('ui/cosmiccodex', 'addArticle', 'co_cat', 'co_mechanics', 'Mechanics'%_t, 'Cosmic Overhaul introduces several QoL improvements to Avorion, including an advanced Bulletin Board interface for filtering missions, new map tools, dynamic respawning of key sectors, and enhanced background simulation logic. The universe is more responsive to your actions, with dedicated tools for managing your empire seamlessly.'%_t, '')
    Player():invokeFunction('ui/cosmiccodex', 'addArticle', 'co_cat', 'co_bounties', 'Bounties & Reputation'%_t, 'Faction bounties dynamically appear when factions declare war or post hits. Players can claim these bounties by hunting marked targets in hostile space. Reputation has been reworked to feel more fluid, with factions reacting more aggressively to hostilities and rewarding loyalty with specialized missions.'%_t, '')
    Player():invokeFunction('ui/cosmiccodex', 'addArticle', 'co_cat', 'co_qol', 'Quality of Life'%_t, 'The Overhaul adds sorting systems for turrets, mass deletion of unneeded emails, map icon toggles, and improved pathfinding for auto-pilot. These small improvements ensure less time clicking menus and more time commanding your fleet.'%_t, '')
end
